UPDATE foods SET long_description = 'Havregryn är hela havreskorn som valsats platta och är en av de mest näringsrika spannmålsprodukterna. De innehåller beta-glukan, en typ av fiber som kan hjälpa till att sänka kolesterol och stabilisera blodsockret. Havregryn är rika på protein (cirka 17 gram per 100 gram), järn, magnesium och B-vitaminer. De innehåller också antioxidanter som avenantramider som är unika för havre. Havregryn har låg glykemiskt index och ger långvarig mättnad. De är perfekta som gröt, i smoothies, bakning eller som müsli. Välj helkorn havregryn för bästa näringsvärde och undvik sockrade varianter.' WHERE slug = 'havregryn';

UPDATE foods SET updated_at = NOW() WHERE slug IN ('agg', 'apple', 'apelsin', 'avokado', 'banan', 'broccoli', 'brod', 'bacon', 'balsamvinager', 'basilika', 'blaber', 'cheddar', 'citron', 'creme-fraiche', 'entrecote', 'fetaost', 'flaskfile', 'grillkorv', 'gurka', 'havregryn');